INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.4.40','cb','cb.adi.4','ЧБ Ади 4.40',40,'দৈবে অপচয় দেখি’ দুইজনে চাহে ।
বালকে দেখিয়া কোন দুঃখ নাহি রহে ॥৪০॥','даиве апачайа декхи’ дуи-джане ча̄хе
ба̄лаке декхийа̄ кона дух̣кха на̄хи рахе',NULL,NULL),('cb.adi.4.41','cb','cb.adi.4','ЧБ Ади 4.41',41,'এইমত প্রতিদিন করেন কৌতুক ।
নাম-করণের কাল হইল সম্মুখ ॥৪১॥','эи-ма̄та̄ прати-дина карена каутука
на̄ма-каран̣ера ка̄ла хаила саммукха',NULL,NULL),('cb.adi.4.42','cb','cb.adi.4','ЧБ Ади 4.42',42,'নীলাম্বর-চক্রবর্ত্তী-আদি বিদ্যাবান্ ।
সর্ব্ব-বন্ধুগণের হইল উপস্থান ॥৪২॥','нӣла̄мбара-чакравартӣ-а̄ди видйа̄ва̄н
сарва-бандху-ган̣ера хаила упастха̄на',NULL,NULL),('cb.adi.4.43','cb','cb.adi.4','ЧБ Ади 4.43',43,'মিলিলা বিস্তর আসি’ পতিব্রতাগণ ।
লক্ষ্মীপ্রায়-দীপ্তা সবে সিন্দূরভূষণ ॥৪৩॥','милила̄ вистара а̄си’ пати-врата̄-ган̣а
лакш̣мӣ-пра̄йа-дӣпта̄ сабе синдӯра-бхӯш̣ан̣а',NULL,NULL),('cb.adi.4.44','cb','cb.adi.4','ЧБ Ади 4.44',44,'নাম থুইবারে সবে করেন বিচার ।
স্ত্রীগণ বোলয়ে এক, অন্যে বোলে আর ॥৪৪॥','на̄ма тхуиба̄ре сабе карена вича̄ра
стрӣ-ган̣а болайе эка, анйе боле а̄ра',NULL,NULL),('cb.adi.4.45','cb','cb.adi.4','ЧБ Ади 4.45',45,'“ইহান অনেক জ্যেষ্ঠ কন্যা-পুত্ত্র নাই ।
শেষ যে জন্ময়ে, তার নাম সে ‘নিমাই’॥”৪৫॥','‘иха̄на анека джйеш̣т̣ха канйа̄-путра на̄и
ш́еш̣а йе джанмайе, та̄ра на̄ма се ’нима̄и’',NULL,NULL),('cb.adi.4.46','cb','cb.adi.4','ЧБ Ади 4.46',46,'বলেন বিদ্বান্ সব করিয়া বিচার ।
“এক নাম যোগ্য হয় থুইতে ইহার ॥৪৬॥','балена видва̄н саба карийа̄ вича̄ра
эка на̄ма йогйа хайа тхуите иха̄ра',NULL,NULL),('cb.adi.4.47','cb','cb.adi.4','ЧБ Ади 4.47',47,'এ শিশু জন্মিলে মাত্র সর্ব্ব-দেশে-দেশে ।
দুর্ভিক্ষ ঘুচিল, বৃষ্টি পাইল কৃষকে ॥৪৭॥','э ш́иш́у джанмиле ма̄тра сарва-деш́е-деш́е
дурбхикш̣а гхучила, вр̣ш̣т̣и па̄ила кр̣ш̣аке',NULL,NULL),('cb.adi.4.48','cb','cb.adi.4','ЧБ Ади 4.48',48,'জগৎ হইল সুস্থ ইহান জনমে ।
পূর্ব্বে যেন পৃথিবী ধরিলা নারায়ণে ॥৪৮॥','джагат хаила сустха иха̄на джанаме
пӯрве йена пр̣тхивӣ дхарила̄ на̄ра̄йан̣е',NULL,NULL),('cb.adi.4.49','cb','cb.adi.4','ЧБ Ади 4.49',49,'অতএব ইহান ‘শ্রীবিশ্বম্ভর’-নাম ।
কুলদীপ কোষ্ঠীতেও লিখিল ইহান ॥৪৯॥','атаева иха̄на ’ш́рӣ-виш́вамбхара’-на̄ма
кула-дӣпа кош̣т̣хӣтео ликхила иха̄на',NULL,NULL),('cb.adi.4.50','cb','cb.adi.4','ЧБ Ади 4.50',50,'‘নিমাই’ যে বলিলেন পতিব্রতাগণ ।
সেই নাম ‘দ্বিতীয়’ ডাকিবে সর্ব্বজন” ॥৫০॥','‘нима̄и’ йе балилена пати-врата̄-ган̣а
сеи на̄ма ‘двитӣйа’ д̣а̄кибе сарва-джана',NULL,NULL),('cb.adi.4.51','cb','cb.adi.4','ЧБ Ади 4.51',51,'সর্ব্ব-শুভক্ষণ নামকরণ-সময়ে ।
গীতা, ভাগবত, বেদ ব্রাহ্মণ পড়য়ে ॥৫১॥','сарва-ш́убха-кш̣ан̣а на̄ма-ка̄ран̣а-самайе
гӣта̄, бха̄гавата, веда бра̄хман̣а падайе',NULL,NULL),('cb.adi.4.52','cb','cb.adi.4','ЧБ Ади 4.52',52,'দেব-নরগণে করয়ে একত্র মঙ্গল ।
হরিধ্বনি, শঙ্খ, ঘণ্টা বাজয়ে সকল ॥৫২॥','дева-нара-ган̣е карайе экатра ман̇гала
хари-дхвани, ш́ан̇кха, гхан̣т̣а̄ ба̄джайе сакала',NULL,NULL),('cb.adi.4.53','cb','cb.adi.4','ЧБ Ади 4.53',53,'ধান্য, পুঁথি, খৈ, কড়ি, স্বর্ণ, রজতাদি যত ।
ধরিবার নিমিত্ত সব কৈলা উপনীত ॥৫৩॥','дха̄нйа, пун̇тхи, каи, кад̣и,
сварн̣а, раджата̄ди йата
дхариба̄ра нимитта саба каила̄ упанӣта',NULL,NULL),('cb.adi.4.54','cb','cb.adi.4','ЧБ Ади 4.54',54,'জগন্নাথ বোলে, “শুন, বাপ বিশ্বম্ভর ।
যাহা চিত্তে লয়, তাহা ধরহ সত্বর” ॥৫৪॥','джаганна̄тха боле, — ‘ш́уна, ба̄па виш́вамбхара
йа̄ха̄ читте лайа, та̄ха̄ дхараха сатвара’',NULL,NULL),('cb.adi.4.55','cb','cb.adi.4','ЧБ Ади 4.55',55,'সকল ছাড়িয়া প্রভু শ্রীশচীনন্দন ।
‘ভাগবত’ ধরিয়া দিলেন আলিঙ্গন ॥৫৫॥','сакала чха̄д̣ийа̄ прабху ш́рӣ-ш́ачӣнандана
‘бха̄гавата’ дхарийа̄ дилена а̄лин̇гана',NULL,NULL),('cb.adi.4.56','cb','cb.adi.4','ЧБ Ади 4.56',56,'পতিব্রতাগণে ‘জয়’ দেয় চারিভিত ।
সবেই বোলেন, — “বড় হইবে পণ্ডিত” ॥৫৬॥','пати-врата̄-ган̣е ’джайа’ дейа ча̄ри-бхита
сабеи болена, — ‘бад̣а хаибе пан̣д̣ита’',NULL,NULL),('cb.adi.4.57','cb','cb.adi.4','ЧБ Ади 4.57',57,'কেহ বোলে, “শিশু বড় হইবে বৈষ্ণব ।
অল্পে সর্ব্বশাস্ত্রের জানিবে অনুভব” ॥৫৭॥','кеха боле, — ‘ш́иш́у бад̣а хаибе ваиш̣н̣ава
алпе сарва-ш́а̄стрера джа̄нибе анубхава’',NULL,NULL),('cb.adi.4.58','cb','cb.adi.4','ЧБ Ади 4.58',58,'যে দিকে হাসিয়া প্রভু চা’ন বিশ্বম্ভর ।
আনন্দে সিঞ্চিত হয় তার কলেবর ॥৫৮॥','йе дике ха̄сийа̄ прабху ча̄’на виш́вамбхара
а̄нанде син̃чита хайа та̄ра калевара',NULL,NULL),('cb.adi.4.59','cb','cb.adi.4','ЧБ Ади 4.59',59,'যে করয়ে কোলে, সে-ই এড়িতে না জানে ।
দেবের দুর্ল্লভে কোলে করে নারীগণে ॥৫৯॥','йе карайе коле, сеи эд̣ите на̄ джа̄не
девера дурлабхе коле каре на̄рӣ-ган̣е',NULL,NULL),('cb.adi.4.60','cb','cb.adi.4','ЧБ Ади 4.60',60,'প্রভু যেই কান্দে, সেইক্ষণে নারীগণ ।
হাতে তালি দিয়া করে হরিসঙ্কীর্ত্তন ॥৬০॥','прабху йеи ка̄нде, сеи-кш̣ан̣е на̄рӣ-ган̣а
ха̄те та̄ле дийа̄ каре хари-сан̇кӣртана',NULL,NULL),('cb.adi.4.61','cb','cb.adi.4','ЧБ Ади 4.61',61,'নাচেন প্রভু কোলের উপরে ।
বিশেষে সকল-নারী হরিধ্বনি করে ॥৬১॥','ш́унийа̄ на̄чена прабху колера упаре
виш́еш̣е сакала-на̄рӣ хари-дхвани каре',NULL,NULL),('cb.adi.4.62','cb','cb.adi.4','ЧБ Ади 4.62',62,'নিরবধি সবার বদনে হরিনাম ।
ছলে বোলায়েন প্রভু,—হেন ইচ্ছা তান ॥৬২॥','ниравадхи саба̄ра вадане хари-на̄ма
>чхале бола̄йена прабху, — хена иччха̄ та̄на',NULL,NULL),('cb.adi.4.63','cb','cb.adi.4','ЧБ Ади 4.63',63,'‘তান ইচ্ছা বিনা কোন কর্ম্ম সিদ্ধ নহে’ ।
বেদে শাস্ত্রে ভাগবতে এই তত্ত্ব কহে ॥৬৩॥','‘та̄на иччха̄ вина̄ кона карма сиддха нахе’
веде ш́а̄стре бха̄гавате эи таттва кахе',NULL,NULL),('cb.adi.4.64','cb','cb.adi.4','ЧБ Ади 4.64',64,'এইমতে করাইয়া নিজ-সঙ্কীর্ত্তন ।
দিনে-দিনে বাড়ে প্রভু শ্রীশচীনন্দন ॥৬৪॥','эи-мате кара̄ийа̄ ниджа-сан̇кӣртана
дине-дине ба̄д̣е прабху ш́рӣ-ш́ачӣнандана',NULL,NULL),('cb.adi.4.65','cb','cb.adi.4','ЧБ Ади 4.65',65,'জানু-গতি চলে প্রভু পরম-সুন্দর ।
কটিতে কিঙ্কিণী বাজে অতি মনোহর ॥৬৫॥','джа̄ну-гати чале прабху парама-сундара
кат̣ите кин̇кин̣ӣ ба̄дже ати манохара',NULL,NULL),('cb.adi.4.66','cb','cb.adi.4','ЧБ Ади 4.66',66,'পরম-নির্ভয়ে সর্ব্ব-অঙ্গনে বিহরে ।
কিবা অগ্নি, সর্প, যাহা দেখে, তাই ধরে ॥৬৬॥','парама-нирбхайе сарва-ан̇гане вихаре
киба̄ агни, сарпа, йа̄ха̄ декхе, та̄и дхаре',NULL,NULL),('cb.adi.4.67','cb','cb.adi.4','ЧБ Ади 4.67',67,'একদিন এক সর্প বাড়ীতে বেড়ায় ।
ধরিলেন সর্পে প্রভু বালক-লীলায় ॥৬৭॥','эка дина эка сарпа ба̄д̣ӣте вед̣а̄йа
дхарилена сарпе прабху ба̄лака-лӣла̄йа',NULL,NULL),('cb.adi.4.68','cb','cb.adi.4','ЧБ Ади 4.68',68,'কুণ্ডলী করিয়া সর্প রহিল বেড়িয়া ।
ঠাকুর থাকিলা তার উপরে শুইয়া ॥৬৮॥','кун̣д̣алӣ карийа̄ сарпа рахила вед̣ийа̄
т̣ха̄кура тха̄кила̄ та̄ра упаре ш́уийа̄',NULL,NULL),('cb.adi.4.69','cb','cb.adi.4','ЧБ Ади 4.69',69,'আথে-ব্যথে সবে দেখি’ ‘হায় হায়’ করে ।
শুইয়া হাসেন প্রভু সর্পের উপরে ॥৬৯॥','а̄тхе-вйатхе сабе декхи’ ‘ха̄йа ха̄йа’ каре
ш́уийа̄ ха̄сена прабху сарпера упаре',NULL,NULL),('cb.adi.4.70','cb','cb.adi.4','ЧБ Ади 4.70',70,'‘গরুড়’ ‘গরুড়’ বলি’ ডাকে সর্ব্বজন ।
পিতামাতা-আদি ভয়ে করয়ে ক্রন্দন ॥৭০॥','‘гаруд̣а’ ‘гаруд̣а’ бали’ да̄ке сарва-джана
пита̄-ма̄та̄-а̄ди бхайе карайе крандана',NULL,NULL),('cb.adi.4.71','cb','cb.adi.4','ЧБ Ади 4.71',71,'চলিলা ‘অনন্ত’ শুনি’ সবার ক্রন্দন ।
পুনঃ ধরিবারে যা’ন শ্রীশচীনন্দন ॥৭১॥','чалила̄ ‘ананта’ ш́уни’ саба̄ра крандана
пунах̣ дхариба̄ре йа̄’на ш́рӣ-ш́ачӣнандана',NULL,NULL),('cb.adi.4.72','cb','cb.adi.4','ЧБ Ади 4.72',72,'ধরিয়া আনিয়া সবে করিলেন কোলে ।
‘চিরজীবী হও’ করি’ নারীগণ বোলে ॥৭২॥','дхарийа̄ а̄нийа̄ сабе карилена коле
‘чира-джӣвӣ хао’ кари’ на̄рӣ-ган̣а боле',NULL,NULL),('cb.adi.4.73','cb','cb.adi.4','ЧБ Ади 4.73',73,'কেহ ‘রক্ষা’ বান্ধে, কেহ পড়ে স্বস্তিবাণী ।
অঙ্গে কেহ দেয় বিষ্ণুপাদোদক আনি’ ॥৭৩॥','кеха ’ракш̣а̄’ ба̄ндхе, кеха пад̣е свасти-ва̄н̣ӣ
ан̇ге кеха дейа виш̣н̣у-па̄докака а̄ни’',NULL,NULL),('cb.adi.4.74','cb','cb.adi.4','ЧБ Ади 4.74',74,'কেহ বোলে, “বালকের পুনর্জ্জন্ম হৈল” ।
কেহ বোলে, “জাতি-সর্প, তেঞি না লঙ্ঘিল” ॥৭৪॥','кеха боле, — ‘ба̄лакера пунар-джанма хаила’
кеха боле, — ‘джа̄ти-сарпа, тен̃и на̄ лан̇гхила’',NULL,NULL),('cb.adi.4.75','cb','cb.adi.4','ЧБ Ади 4.75',75,'হাসে প্রভু গৌরচন্দ্র সবারে চাহিয়া ।
পুনঃ পুনঃ যায়, সবে আনেন ধরিয়া ॥৭৫॥','ха̄се прабху гаурачандра саба̄ре ча̄хийа̄
пунах̣ пунах̣ йа̄йа, сабе а̄нена дхарийа̄',NULL,NULL),('cb.adi.4.76','cb','cb.adi.4','ЧБ Ади 4.76',76,'ভক্তি করি’ যে এ-সব বেদগোপ্য শুনে ।
সংসার-ভুজঙ্গ তারে না করে লঙ্ঘনে ॥৭৬॥','бхакти кари’ йе э-саба веда-гопйа ш́уне
сам̇са̄ра-бхуджан̇га та̄ре на̄ каре лан̇гхане',NULL,NULL),('cb.adi.4.77','cb','cb.adi.4','ЧБ Ади 4.77',77,'এইমত দিনে-দিনে শ্রীশচীনন্দন ।
হাঁটিয়া করয়ে প্রভু অঙ্গনে ভ্রমণ ॥৭৭॥','эи-мата дине-дине ш́рӣ-ш́ачӣнандана
ха̄н̇т̣ийа̄ карйе прабху ан̇гане бхрамана',NULL,NULL),('cb.adi.4.78','cb','cb.adi.4','ЧБ Ади 4.78',78,'জিনিয়া কন্দর্প-কোটি সর্ব্বাঙ্গের রূপ ।
চান্দের লাগয়ে সাধ দেখিতে সে-মুখ ॥৭৮॥','джинийа̄ кандарпа-кот̣и сарва̄н̇гера рӯпа
ча̄ндера ла̄гайе са̄дха декхите се-мукха',NULL,NULL),('cb.adi.4.79','cb','cb.adi.4','ЧБ Ади 4.79',79,'সুবলিত মস্তকে চাঁচর ভাল-কেশ ।
কমল-নয়ন,—যেন গোপালের বেশ ॥৭৯॥','сувалита мастаке ча̄н̇чара бха̄ла-кеш́а
